using BgCommon.Script.Runtime.Configuration;namespace BgCommon.Script.Runtime.Services;/// <summary>/// 遥测提供程序基类./// </summary>public abstract class TelemetryProviderBase : ITelemetryProvider{    private Exception? lastError;    /// <summary>    /// Initializes a new instance of the <see cref="TelemetryProviderBase"/> class.    /// </summary>    protected TelemetryProviderBase()    {    }    /// <summary>    /// Gets 最后一次发生的错误.    /// </summary>    public Exception? LastError    {        get => this.lastError;        private set        {            // 设置错误值并触发变更通知            this.lastError = value;            this.LastErrorChanged?.Invoke();        }    }    /// <summary>    /// 当最后一次错误发生改变时触发的事件.    /// </summary>    public event Action? LastErrorChanged;    /// <summary>    /// 初始化遥测提供程序.    /// </summary>    /// <param name="version">应用程序版本.</param>    /// <param name="settings">应用程序设置.</param>    public virtual void Initialize(string version, IApplicationSettings settings)    {        // 注册全局未处理异常处理        // 注册未观测到的 Task 异常处理        AppDomain.CurrentDomain.UnhandledException += this.CurrentDomainOnUnhandledException;        TaskScheduler.UnobservedTaskException += this.TaskSchedulerOnUnobservedTaskException;    }    /// <summary>    /// 报告一个异常.    /// </summary>    /// <param name="exception">要报告的异常对象.</param>    public void ReportError(Exception exception)    {        // 调用统一的异常处理逻辑        this.HandleException(exception);    }    /// <summary>    /// 清除最后一次发生的错误记录.    /// </summary>    public void ClearLastError()    {        this.LastError = null;    }    /// <summary>    /// 统一处理异常逻辑.    /// </summary>    /// <param name="exception">捕获到的异常对象.</param>    protected void HandleException(Exception exception)    {        // 如果是操作取消异常，则忽略不计入错误日志        if (exception is OperationCanceledException)        {            return;        }        this.LastError = exception;    }    /// <summary>    /// 处理任务调度器中未观测到的异常.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="args">未观测异常事件参数.</param>    private void TaskSchedulerOnUnobservedTaskException(object? sender, UnobservedTaskExceptionEventArgs args)    {        // 展开聚合异常并处理其内部异常        this.HandleException(args.Exception!.Flatten().InnerException!);    }    /// <summary>    /// 处理应用程序域中未处理的异常.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="args">未处理异常事件参数.</param>    private void CurrentDomainOnUnhandledException(object? sender, UnhandledExceptionEventArgs args)    {        // 强制转换异常对象并处理        this.HandleException((Exception)args.ExceptionObject);    }}